class AuthServiceServicer:
    def Login(self, request, context):
        username = request.username
        password = request.password
        
        if username in USERS_DB:
            stored_password = USERS_DB[username]['password']
            if self._hash_password(password) == stored_password:
                token = self._generate_token(username)
                return LoginResponse(success=True, token=token, message='Login successful')
        
        return LoginResponse(success=False, token='', message='Invalid credentials')
    
    def Register(self, request, context):
        username = request.username
        password = request.password
        email = request.email
        
        if username in USERS_DB:
            return RegisterResponse(success=False, message='Username already exists')
        
        USERS_DB[username] = {
            'password': self._hash_password(password),
            'email': email
        }
        USER_DATA_DB[username] = ''
        
        return RegisterResponse(success=True, message='Registration successful')
    
    def ValidateToken(self, request, context):
        token = request.token
        
        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
            username = payload.get('username')
            
            if username and username in USERS_DB:
                return ValidateTokenResponse(valid=True, username=username)
        except jwt.ExpiredSignatureError:
            return ValidateTokenResponse(valid=False, username='')
        except jwt.InvalidTokenError:
            return ValidateTokenResponse(valid=False, username='')
        
        return ValidateTokenResponse(valid=False, username='')
    
    def _hash_password(self, password):
        return hashlib.sha256(password.encode()).hexdigest()
    
    def _generate_token(self, username):
        payload = {
            'username': username,
            'exp': datetime.utcnow() + timedelta(hours=24)
        }
        return jwt.encode(payload, SECRET_KEY, algorithm='HS256')


